#include <Wire.h>
#include <Adafruit_GFX.h>
#include <Adafruit_SSD1306.h>
#include <DHT.h>
#define SCREEN_WIDTH 128
#define SCREEN_HEIGHT 64
Adafruit_SSD1306 display(
  SCREEN_WIDTH,
  SCREEN_HEIGHT,
  &Wire,
  -1
);
#define RED 25
#define GREEN 26
#define BLUE 33
#define BTN_LEFT 14
#define BTN_SELECT 12
#define BTN_RIGHT 18
#define BUZZER 27
#define PIR 13
#define DHTPIN 4
#define DHTTYPE DHT11
#define POT_PIN 35
DHT dht(DHTPIN,DHTTYPE);
enum Mood {
  HAPPY,
  SLEEPY,
  THIRSTY,
  HOT,
  EXCITED
};
Mood mood = HAPPY;
unsigned long lastMotion = 0;
unsigned long lastSensorRead = 0;
unsigned long excitedStart = 0;
bool excited = false;
enum Screen
{
  SCREEN_PLANT,
  SCREEN_STATS,
  SCREEN_STATUS
};
Screen currentScreen = SCREEN_PLANT;
float temperature = 0;
float humidity = 0;
bool lastLeft = HIGH;
bool lastRight = HIGH;
bool lastSelect = HIGH;
unsigned long lastWarningBeep = 0;
int animationFrame = 0;
int plantOffset = 0;
bool blinking = false;
unsigned long lastBlink = 0;
unsigned long blinkStart = 0;
unsigned long lastAnimation = 0;
void setRGB(bool r,bool g,bool b)
{
  digitalWrite(RED,r);
  digitalWrite(GREEN,g);
  digitalWrite(BLUE,b);
}
void updateRGB()
{
  switch(mood)
  {
    case HAPPY:
      setRGB(0,1,0);
      break;
    case SLEEPY:
      setRGB(0,0,1);
      break;
    case THIRSTY:
      setRGB(0,0,1);
      break;
    case HOT:
      setRGB(1,0,0);
      break;
    case EXCITED:
      setRGB(1,1,0);
      break;
  }
}
void drawPlant()
{
display.clearDisplay();
int sway = animationFrame ? 2 : -2;
int y = plantOffset;
display.fillCircle(
42+sway,
18+y,
8,
SSD1306_WHITE
);
display.fillCircle(
86-sway,
18+y,
8,
SSD1306_WHITE
);
display.fillRoundRect(
35,
20+y,
58,
30,
10,
SSD1306_WHITE
);
if(blinking || mood==SLEEPY)
{
display.drawLine(
52,
33+y,
58,
33+y,
SSD1306_BLACK
);
display.drawLine(
70,
33+y,
76,
33+y,
SSD1306_BLACK
);
}
else
{
  display.fillCircle(
    55,
    33+y,
    3,
    SSD1306_BLACK
  );
  display.fillCircle(
    73,
    33+y,
    3,
    SSD1306_BLACK
  );
  if(mood == THIRSTY)
  {
    display.setTextSize(1);
    display.setTextColor(SSD1306_BLACK);
    display.setCursor(52,38+y);
    display.print(";");
    display.setCursor(70,38+y);
    display.print(";");
  }
}
// why are you looking through my coe ;-; its so basic u wont learn anything from tis ;-;
if(mood==HAPPY)
{
  display.drawLine(
    58,
    40+y,
    61,
    43+y,
    SSD1306_BLACK
  );
  display.drawLine(
    61,
    43+y,
    67,
    43+y,
    SSD1306_BLACK
  );
  display.drawLine(
    67,
    43+y,
    70,
    40+y,
    SSD1306_BLACK
  );
}
else if(mood==EXCITED)
{
display.fillCircle(
64,
40+y,
4,
SSD1306_BLACK
);
display.drawPixel(25,12,SSD1306_WHITE);
display.drawPixel(100,12,SSD1306_WHITE);
display.drawPixel(22,18,SSD1306_WHITE);
}
else if(mood==THIRSTY)
{
display.drawLine(
60,
43+y,
64,
39+y,
SSD1306_BLACK
);
display.drawLine(
64,
39+y,
68,
43+y,
SSD1306_BLACK
);
display.fillCircle(
90,
35,
3,
SSD1306_WHITE
);
display.drawLine(
90,
31,
90,
27,
SSD1306_WHITE
);
}
else if(mood==HOT)
{
  display.drawLine(
    60,
    41+y,
    64,
    39+y,
    SSD1306_BLACK
  );
  display.drawLine(
    64,
    39+y,
    68,
    41+y,
    SSD1306_BLACK
  );
}
else
{
display.drawLine(
60,
40+y,
68,
40+y,
SSD1306_BLACK
);
}
if(mood==SLEEPY)
{
display.setTextSize(1);
display.setTextColor(SSD1306_WHITE);
display.setCursor(
90,
10
);
display.print("Z");
display.setCursor(
98,
5
);
display.print("Z");
}
display.drawLine(
64,
50+y,
64,
57+y,
SSD1306_WHITE
);
// dammm holy did was hard
display.fillRect(
45,
55,
38,
8,
SSD1306_WHITE
);
display.display();
}
void drawStats()
{
  display.clearDisplay();
  display.setTextSize(1);
  display.setTextColor(SSD1306_WHITE);
  display.setCursor(0,0);
  display.print("Plant Stats");
  display.setCursor(0,18);
  display.print("Temp: ");
  display.print(temperature);
  display.print(" C");
  display.setCursor(0,36);
  display.print("Humidity: ");
  display.print(humidity);
  display.print("%");
  display.display();
}
void drawStatus()
{
  display.clearDisplay();
  display.setTextSize(2);
  display.setCursor(0,0);
  display.print("Status");
  display.setTextSize(1);
  display.setCursor(0,28);
  if(mood==SLEEPY)
    display.print("Sleeping");
  else
    display.print("Awake");
  display.display();
}
void updateAnimation()
{
  unsigned long now = millis();
  if(now - lastAnimation > 500)
  {
    lastAnimation = now;
    animationFrame = !animationFrame;
    if(animationFrame)
      plantOffset = 1;
    else
      plantOffset = -1;
  }
  if(!blinking && now-lastBlink > random(3000,6000))
  {
    blinking = true;
    blinkStart = now;
  }
  if(blinking && now-blinkStart > 120)
  {
    blinking = false;
    lastBlink = now;
  }
}
void clickBeep()
{
  ledcWriteTone(BUZZER, 2000);
  delay(40);
  ledcWriteTone(BUZZER, 0);
}
void setup()
{
  Serial.begin(115200);
  display.begin(
    SSD1306_SWITCHCAPVCC,
    0x3C
  );
  dht.begin();
  pinMode(RED,OUTPUT);
  pinMode(GREEN,OUTPUT);
  pinMode(BLUE,OUTPUT);
  pinMode(BTN_LEFT,INPUT_PULLUP);
  pinMode(BTN_SELECT,INPUT_PULLUP);
  pinMode(BTN_RIGHT,INPUT_PULLUP);
  pinMode(PIR,INPUT);
  pinMode(BUZZER,OUTPUT);
  ledcAttach(BUZZER, 2000, 8);
  pinMode(POT_PIN,INPUT);
  updateRGB();
}
void loop()
{
  unsigned long now = millis();
if(digitalRead(PIR))
{
  mood = EXCITED;
  excited = true;
  excitedStart = now;
  lastMotion = now;
}
if(excited && now - excitedStart > 5000)
{
  excited = false;
  if(mood == EXCITED)
    mood = HAPPY;
}
if(now - lastMotion > 30000)
{
  if(mood != HOT && mood != THIRSTY)
  {
    mood = SLEEPY;
  }
}
  if(now-lastSensorRead > 2000)
  { 
    lastSensorRead = now;
  temperature = dht.readTemperature();
  humidity = dht.readHumidity();
    if(temperature > 30)
      mood = HOT;
    else if(humidity < 40)
      mood = THIRSTY;
    else if(mood != EXCITED && mood != SLEEPY)
      mood = HAPPY;
  }
if ((temperature > 30 || humidity < 40) &&
    millis() - lastWarningBeep > 3000)
{
  ledcWriteTone(BUZZER, 1000);
  delay(100);
  ledcWriteTone(BUZZER, 0);
  lastWarningBeep = millis();
}
int potValue = analogRead(POT_PIN);
int brightness = map(
  potValue,
  0,
  4095,
  10,
  255
);
// finally done i am freeee!!! tatsu i hopeu like my lil plant :3
display.ssd1306_command(SSD1306_SETCONTRAST);
display.ssd1306_command(brightness);
  updateRGB();
  updateAnimation();
bool left = digitalRead(BTN_LEFT);
bool right = digitalRead(BTN_RIGHT);
bool select = digitalRead(BTN_SELECT);
if(left==LOW && lastLeft==HIGH)
{
  clickBeep();
  if(currentScreen == SCREEN_PLANT)
    currentScreen = SCREEN_STATUS;
  else
    currentScreen = (Screen)(currentScreen - 1);
}
if(right==LOW && lastRight==HIGH)
{
  clickBeep();
  if(currentScreen == SCREEN_STATUS)
    currentScreen = SCREEN_PLANT;
  else
    currentScreen = (Screen)(currentScreen + 1);
}
if(select==LOW && lastSelect==HIGH)
{
  clickBeep();
  currentScreen=SCREEN_PLANT;
}
lastLeft=left;
lastRight=right;
lastSelect=select;
switch(currentScreen)
{
  case SCREEN_PLANT:
    drawPlant();
    break;
  case SCREEN_STATS:
    drawStats();
    break;
  case SCREEN_STATUS:
    drawStatus();
    break;
}
}
